document.addEventListener("DOMContentLoaded",function(){const e=document.querySelector(".photo-track");if(!e)return;function t(){const t=window.innerWidth,i=window.innerHeight,n=Math.floor(t/8),s=Math.floor(t/4),o=e.querySelectorAll(".photo-item");o.forEach((e)=>{const o=n+Math.random()*(s-n),i=.7+Math.random()*.6;e.style.width=`${o}px`,e.style.height=`${Math.floor(o*i)}px`;const a=(Math.random()-.5)*10;e.style.transform=`rotate(${a}deg)`})}t();let n;window.addEventListener("resize",()=>{clearTimeout(n),n=setTimeout(t,200)})})